import{c as t,Q as a,j as s,m as n}from"./chunks/framework.D9IbVcwA.js";const h=JSON.parse('{"title":"Init 线程重构","description":"","frontmatter":{"title":"Init 线程重构"},"headers":[],"relativePath":"notes/028e/001_init_thread_refactor_mmio_collision.md","filePath":"notes/028e/001_init_thread_refactor_mmio_collision.md","lastUpdated":1779686691000}'),d={name:"notes/028e/001_init_thread_refactor_mmio_collision.md"};function i(o,e,c,r,p,l){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="_028e-·-重构调度器启动为-linux-init-线程模型-—-排查笔记" tabindex="-1">028e · 重构调度器启动为 Linux init 线程模型 — 排查笔记 <a class="header-anchor" href="#_028e-·-重构调度器启动为-linux-init-线程模型-—-排查笔记" aria-label="Permalink to &quot;028e · 重构调度器启动为 Linux init 线程模型 — 排查笔记&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>将 <code>Scheduler::init()</code> 从 <code>run_concurrent_stress()</code> 中提取出来，对齐 Linux 的 init 线程模型：</p><ul><li>boot CPU 上下文 → boot task（类似 PID 0 idle）</li><li>spawn <code>kernel_init</code> 线程（类似 PID 1）负责文件系统挂载和 shell 启动</li><li>同时修复 <code>launch_first_user()</code> 中手动创建零初始化 <code>static Task shell_task{}</code> 的问题</li></ul><h2 id="变更清单" tabindex="-1">变更清单 <a class="header-anchor" href="#变更清单" aria-label="Permalink to &quot;变更清单&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文件</th><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><code>kernel/proc/init.hpp</code></td><td>新建</td><td>声明 <code>kernel_init_thread()</code></td></tr><tr><td><code>kernel/proc/init.cpp</code></td><td>新建</td><td>init 线程：ext2 挂载 + VFS + launch_first_user</td></tr><tr><td><code>kernel/arch/x86_64/memory_layout.hpp</code></td><td>新建</td><td>统一内核虚拟内存布局定义</td></tr><tr><td><code>kernel/main.cpp</code></td><td>修改</td><td>Scheduler::init() 直接调用，spawn init 线程，删除 stress/键盘轮询</td></tr><tr><td><code>kernel/arch/x86_64/usermode.cpp</code></td><td>修改</td><td>删除 shell_task，使用调度器管理的当前 Task</td></tr><tr><td><code>kernel/drivers/ahci/ahci.hpp</code></td><td>修改</td><td>添加 instance()/set_instance() 静态方法</td></tr><tr><td><code>kernel/drivers/ahci/ahci.cpp</code></td><td>修改</td><td>实现 instance/set_instance，MMIO_VIRT_BASE 引用统一布局</td></tr><tr><td><code>kernel/proc/process.cpp</code></td><td>修改</td><td>next_stack_vaddr 引用统一布局</td></tr><tr><td><code>kernel/fs/ext2.cpp</code></td><td>修改</td><td>EXT2_DMA_VIRT_BASE 引用统一布局</td></tr><tr><td><code>kernel/stress/stress_test.cpp</code></td><td>删除</td><td>整个 stress 目录移除</td></tr><tr><td><code>kernel/CMakeLists.txt</code></td><td>修改</td><td>添加 proc/init.cpp，删除 stress_test.cpp</td></tr></tbody></table><hr><h2 id="排查记录" tabindex="-1">排查记录 <a class="header-anchor" href="#排查记录" aria-label="Permalink to &quot;排查记录&quot;">​</a></h2><h3 id="问题-1-ext2-mount-失败-—-command-timeout" tabindex="-1">问题 1：ext2 mount 失败 — &quot;command timeout&quot; <a class="header-anchor" href="#问题-1-ext2-mount-失败-—-command-timeout" aria-label="Permalink to &quot;问题 1：ext2 mount 失败 — &quot;command timeout&quot;&quot;">​</a></h3><p><strong>现象</strong>：重构后 ext2 挂载报 <code>Port 1: command timeout</code>，但 AHCI 初始化阶段 Port 1 检测到设备（<code>SSTS=0x113 DET=3</code>）。</p><p><strong>初步假设</strong>：调度器抢占导致 AHCI DMA 轮询被打断，浪费了超时时间。</p><p><strong>验证</strong>：在 ext2 挂载外加 <code>InterruptGuard</code> 关中断，问题依旧。排除抢占假设。</p><h3 id="问题-2-根因-内核栈虚拟地址覆盖-ahci-mmio-映射" tabindex="-1">问题 2（根因）：内核栈虚拟地址覆盖 AHCI MMIO 映射 <a class="header-anchor" href="#问题-2-根因-内核栈虚拟地址覆盖-ahci-mmio-映射" aria-label="Permalink to &quot;问题 2（根因）：内核栈虚拟地址覆盖 AHCI MMIO 映射&quot;">​</a></h3><p><strong>关键发现</strong>：在 init 线程中打印 Port 1 的 SSTS 寄存器：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[AHCI] Port 1: SSTS=0x113 DET=3 SIG=0xffffffff   ← AHCI init 时，设备在线</span></span>
<span class="line"><span>[INIT] Port 1 SSTS=0x0 before mount                ← init 线程中，设备消失！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Port 1 的设备状态从 <code>0x113</code> 变成了 <code>0x0</code>。MMIO 寄存器读出全零 = 页表映射被覆盖。</p><p><strong>根因分析</strong>：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AHCI MMIO 虚拟基址 (ahci.cpp):  0xFFFF800000100000</span></span>
<span class="line"><span>内核栈虚拟起始  (process.cpp):  0xFFFF800000100000  ← 完全相同！</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><code>TaskBuilder::build()</code> 为每个任务分配 4 页内核栈，通过 <code>g_vmm.map()</code> 映射到 <code>0xFFFF800000100000</code> 起始的虚拟地址。这覆盖了 AHCI BAR5 的 MMIO 页表项：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Scheduler::init() 创建 idle task → 栈映射到 0xFFFF800000100000 → 覆盖 AHCI MMIO</span></span>
<span class="line"><span>TaskBuilder 创建 kernel_init   → 栈映射到 0xFFFF800000104000 → 覆盖 AHCI cmdlist/fis</span></span>
<span class="line"><span>TaskBuilder 创建 boot task     → 栈映射到 0xFFFF800000108000 → 进一步覆盖</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>为什么重构前没暴露</strong>：重构前 <code>Scheduler::init()</code> 在 <code>run_concurrent_stress()</code> 中调用，AHCI init 和 ext2 mount 都在 <code>kernel_main()</code> 中（调度器启动前）完成，此时还没有内核栈映射，MMIO 区域完好。</p><p><strong>修复</strong>：创建 <code>kernel/arch/x86_64/memory_layout.hpp</code>，统一管理内核虚拟内存布局：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>KMEM_HEAP_BASE  = 0xFFFF800000000000  (1 MB)</span></span>
<span class="line"><span>KMEM_MMIO_BASE  = 0xFFFF800000100000  (256 KB)</span></span>
<span class="line"><span>KMEM_STACK_BASE = 0xFFFF800000150000  ← MMIO 之后</span></span>
<span class="line"><span>KMEM_DMA_BASE   = 0xFFFF800000250000</span></span>
<span class="line"><span>KMEM_EXT2_DMA_BASE = 0xFFFF800000350000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>所有模块通过 <code>base + size</code> 计算地址，新增区域只需插入一行并调整后续基址。</p><h3 id="问题-3-launch-first-user-的-static-task-绕过调度器" tabindex="-1">问题 3：launch_first_user() 的 static Task 绕过调度器 <a class="header-anchor" href="#问题-3-launch-first-user-的-static-task-绕过调度器" aria-label="Permalink to &quot;问题 3：launch_first_user() 的 static Task 绕过调度器&quot;">​</a></h3><p><strong>现象</strong>：<code>usermode.cpp:167</code> 手动创建 <code>static Task shell_task{}</code>，零初始化、无内核栈、tid=0、不在运行队列。</p><p><strong>影响</strong>：</p><ul><li><code>sys_exit</code> 调用 <code>Scheduler::current()</code> 返回这个伪 Task，标记 Dead 后 yield，但该 Task 不在运行队列中</li><li>没有有效的 CpuContext，如果调度器尝试切回它会崩溃</li></ul><p><strong>修复</strong>：使用调度器管理的当前 Task（kernel_init 线程），只更新 <code>addr_space</code> 和 <code>cwd</code>。<code>user_space</code> 改为 placement new 在 static buffer 上（避免 <code>__dso_handle</code> 链接错误，因为 AddressSpace 有析构器）。</p><h3 id="问题-4-ahci-全局实例的跨翻译单元访问" tabindex="-1">问题 4：AHCI 全局实例的跨翻译单元访问 <a class="header-anchor" href="#问题-4-ahci-全局实例的跨翻译单元访问" aria-label="Permalink to &quot;问题 4：AHCI 全局实例的跨翻译单元访问&quot;">​</a></h3><p><strong>现象</strong>：<code>init.cpp</code> 在 <code>big_kernel_common</code> 中，<code>g_kernel_ahci</code> 定义在 <code>main.cpp</code> 中。test binary 没有 <code>g_kernel_ahci</code> 定义导致链接失败。</p><p><strong>修复</strong>：在 AHCI 类中添加 <code>static instance()/set_instance()</code> 方法，遵循现代 C++ 封装原则。<code>main.cpp</code> 初始化后调用 <code>set_instance()</code>，<code>init.cpp</code> 通过 <code>AHCI::instance()</code> 访问。</p>`,32)])])}const _=t(d,[["render",i]]);export{h as __pageData,_ as default};
